INSERT INTO Therapists(id, name, certified, image_Url, bio, location, url) VALUES
(1, 'Kezzia Quintyne-Hilaire', 'LMHC, CASAC, Counselor', '', 'Your feelings are valid! As a Licensed Mental Health Counselor and a Black therapist in NYC, I understand the value of receiving quality therapy services. My practice is dedicated to helping women of color keep their crowns on straight. I specialize in trauma, womens issues, and anxiety. My primary therapeutic focus is Eye Movement Desensitization and Reprocessing (EMDR), which uses bilateral stimulation to help replace traumatic memories. Healing occurs through various approaches, so I also use multiple therapies to help my clients reduce depression, anxiety, work stress, and emotional distress.', 'Brooklyn','https://www.kqhcounseling.com/contact-black-female-therapist-nyc'),
(2, 'Keanu M. Jackson', 'Clinical Social Work/Therapist, LCSW', '', 'In our sessions, we will delve into the complex tapestry of your relationships, exploring the dynamics of intimacy and connection with honesty and vulnerability. From navigating communication challenges to deepening emotional intimacy, I provide practical tools and insightful guidance for you to foster healthier, more fulfilling connections with others and yourself. What excites me most about this work is being able to share space with those within my own communities. As a kinky, queer, Black therapist I recognize that what we need is the opportunity to expand our horizons in an effort to dive deeper into the richness of who we are.', 'Brooklyn', 'https://www.keanumjackson.com'),
(3, 'Queen Ravenden', 'Art Therapist, R-DMT, LCAT', '',	'Greetings and peace to you, divine being. I am a black, caribbean american, creative arts therapist providing safe, affirming, uplifting, and holistic healing. My therapeutic style uses a strength-based approach while incorporating creative art therapy techniques and catering to the balance & overall wellbeing of the mind, body, & soul. I work with individuals to overcome low self-esteem, self-doubt, anxiety, past traumas, and depression using creative arts therapy.', 'Brooklyn', 'https://www.mindbodysoulvirtualwellnesscenter.com'),
(4, 'Chelsea Thornton', 'Licensed Master Social Work, LMSW', '', 'I’m passionate in analyzing interpersonal connections through a multicultural lens. I frequently utilize CBT, EFT (Emotionally Focused Therapy), ARA (the Ackerman Relational Approach), and mindfulness techniques as we learn and embrace the many overlapping identities that exist within you. I provide services to children, teens, adults, couples, and families.', 'Brooklyn', 'https://www.zocdoc.com/professional/chelsea-thornton-lmsw-480442'),
(5, 'The Healing Collective', 'Clinical Social Work/Therapist, LCSW','', 'The Healing Collective is a New York-based therapeutic group practice that centers the healing of Black folks, Indigenous folks, and non-Black folks of color. We offer telehealth services to individuals (youth and adults), couples, and families throughout New York and New Jersey. We also offer coaching services throughout the United States. The Healing Collective believes that every being is worthy of healing and that our healing comes from within. We’d be honored if you chose us for your healing journey.', 'Brooklyn', 'https://www.thehealingcollectivepractice.com'),
(6, 'Shani Graves', 'Counselor, LMHC', '', 'Maybe its been two months or two years, but it has not been easy. Whether its your personal life, work life, familial, platonic, or romantic relationships. You may have begun to feel overwhelmed,annoyed, stressed, lonely and even depressed. You compare yourself to others and wonder why your life is not a reflection of the work you have put into it or how you imagined it would be. If any of these feelings have taken root in your life, contact me and my team today. Our role at SG Wellness is to create a space for Black, Latinx and People of Color to begin exploring patterns and work towards change. Together we can work to get you out of the haze, reduce pressure and set boundaries for yourself and others.', 'Brooklyn', 'https://sgcounselingnyc.com'),
(7, 'Tanner Kaleb Williams', 'Licensed Master Social Worker, LMSW', '', 'Hello there :) I am Tanner (he/him) a Black, queer, art and creativity lover based in Brooklyn, NY on occupied Lenape land. If you are searching for a therapist who truly listens and collaborates rather than just gives advice and diagnoses, I would be honored to connect with you. I focus on embracing radical acceptance, fostering community based care, and moving beyond labeling our experiences. If you are in need of a safe space to be your authentic self, we might be a perfect match. Please reach out! I am eager to hear about what is bringing you to therapy.', 'Manhattan', 'https://www.inclusivetherapists.com/new-york/brooklyn/tanner-williams'),
(8, 'Cloricea Brooks', 'Counselor, MA, LMHC, CASAC-T', '', 'Everyday we tell ourselves stories through our thoughts. These stories stem from our lived experiences, which are inseparable from our cultural identities. Life challenges like job stress, relationship issues, trauma, and grief can lead to stories that highlight fear, anger, mistrust, and sadness, resulting in detachment and difficulty feeling joy. I believe that restoring genuine connections with yourself and others is a powerful antidote. Together we will explore cognitive and behavioral interventions to change what you can, while intentionally accepting the unchangeable in a compassionate space.', 'Manhattan', 'https://headway.co/providers/cloricea-brooks'),
(9, 'Dr. Gary Dillon', 'Psychologist, PhD', '', 'Frustrated, stuck, or unfulfilled in an area of your life? You are not alone. Amid a global pandemic, along with the current social and political climate, knowing how to begin healing can be a challenge. Life is complicated and it can be difficult to reach out to gain the support and encouragement that you need to succeed. But don’t worry, I’ll be your ally on this journey - supporting and helping you along the way. As a Black male therapist in NYC, I specialize in working with individuals & couples, who at times feel powerless and are often marginalized - including immigrants, people of color, and members of the LGBTQIA+ community.', 'Manhattan', 'https://www.allypsychotherapy.com'),
(10, 'Racine Renee Henry', 'Marriage & Family Therapist, PhD, LMFT', '', 'The word Sankofa means "one must go back in order to move forward". The idea is that in order to move forward into our highest potential, we must use the best of what was in our past. As a relational therapist who primarily works from a Solution-Focused approach, the word Sankofa reflects my belief that learning from our experiences in the past can contribute to healing in the present and future. I believe we are all capable of change through an effective solution. I have experience bringing about the changes that will lead to a healthier and happier life. I specialize in treating couples from marginalized and minority groups. I have done extensive research and training on issues commonly experienced by women of all backgrounds, within the Black community and within Black romantic relationships.', 'Staten Island', 'https://www.sankofatherapynyc.com'),
(11, 'Amira R Martin', 'Clinical Social Work/Therapist, LCSW-R', '', 'I am here to provide you with warm and compassionate support as you navigate lifes challenges. Your journey is unique, and I want you to feel genuinely heard and understood. If you are facing issues like Depression, Anxiety, difficult relationships and work-related struggles, I am here to help you navigate and recover from these challenges. My commitment is to create a safe and supportive space for your healing. Together, we will address your struggles and challenges while fostering your personal growth and resilience. You can achieve emotional well-being, navigate life transitions, and ultimately lead a more fulfilling life.', 'Brooklyn', 'https://www.amiraforher.com'),
(12, 'Vanessa A. Williams', 'Counselor, LMHC', '', '"There is no greater agony than bearing the untold story inside you." - Maya Angelou. Each person’s story shapes them and a burden to carry alone that is relieved when met with empathy. I consider it an honor to be present with clients as they share their untold story, gain greater self-knowledge, and manifest the story that is yet to come. I come from a place of curiosity and non-judgement around each individual’s lived experience. I hope to create a warm, accepting space where you can be your authentic self, feel safe to express your uncensored thoughts and share both laughter and tears.', 'Brooklyn', 'https://rootsandbranchestherapy.nyc/vanessa-williams/'),
(13, 'Dwayne James', 'Clinical Social Work/Therapist, MSW, LCSW', '' ,'I say seeking therapy is nothing close to a sign of weakness but the biggest sign of strength you can possibly have. My name is Dwayne James, and I am a Black male clinician. With over five years of clinical therapeutic experience, my passion for social-emotional support continues to shine through with every client interaction. My overall therapeutic goal is to ensure folks get the essential tools to add to their tool kit in times of need while also providing the utmost support for their social and emotional needs. My work is rooted in cultural sensitivity and recognizes that clients are experts in their own experiences.', 'Brooklyn', 'https://headway.co/providers/dwayne-james?utm_source=pem&utm_medium=direct_link&utm_campaign=94657'),
(14, 'Uzoma Chibundu', 'Clinical Social Work/Therapist, LMSW', '','My therapeutic approach is collaborative, warm, authentic and holistic. I believe the client is the expert of their experiences and my purpose is to assist them in their journey toward healing. I help clients through an array of talk therapy, story telling and treatment-centered homework. I operate from a relational, intersectional, and anti-oppressive lens. Everyone has their own therapeutic journey, and who we bring on this journey is up to us. Ones journey towards healing can be a culmination of tough conversations, laughter, and tears. My hope is that we all find people to accompany us on our therapeutic journey. Lets schedule a free consultation to see we would be a good fit.', 'Brooklyn', 'https://www.psychologytoday.com/us/therapists/uzoma-chibundu-brooklyn-ny/1051407'),
(15, 'Nafisa Clay', 'Counselor, LMHC', '','My style includes respect, empowerment and solution exploration. I have been trained in a range of modalities inclusive of motivational interviewing, cognitive behavioral therapy, solution-focused therapy and strength-based therapy. Your decision to explore therapy to help you navigate change, difficult feelings and/or behaviors can be the first step in embracing more overall wellness and life satisfaction. If you are ready to take the step, I am here to support you in your journey. I look forward to working alongside you!','Manhattan', 'https://nafisah-clay.clientsecure.me'),
(16, 'Therapy For Black Men', 'Counselor, LMHC' , '', 'You are worthy of care, of healing, of peace. Life can feel overwhelming sometimes whether its the pressures you face every day, the weight of expectations, or the silent struggles that no one else sees. You don’t have to carry it all on your own. Therapy for Black Men offers a safe space to connect with therapists and coaches who look like you, understand your experiences, and want to help you heal.', 'Manhattan', 'https://therapyforblackmen.org'),
(17, 'Zakiyyah Abdul-Mateen', 'Clinical Social Work/Therapist, LCSW', '', 'I am an EMDR-trained, child/adolescent & young adult psychotherapist who has created a safe space providing services to strengthen the most vulnerable populations. I use meditative practices to reduce anxiety associated with traumatic memory. Things such as childhood traumas, environmental factors, depression, anxiety and adjustments can all effect the way one interprets life. For Caregivers: With treatment catered to your childs specific needs, I will begin the process of helping them heal through therapeutic play, relaxation techniques, listening skills, while also engaging the family to formulate best treatment for the child.', 'Manhattan', 'https://www.zakiyyah-am.com'),
(18, 'Camille Lester', 'Counselor, LMHC, LCPC, MS, NCC', '', 'Are you ready to start addressing the patterns you keep saying you will? Deepen emotional intimacy? Explore feeling safe in vulnerability? Stop feeling stuck when attempting to understand or communicate your needs? Begin breaking down what it means to “break generational curses” and actually start breaking them? Rest assured, you are in the right place. I am happy you are here!', 'Manhattan', 'https://www.therapywithc.com'),
(19, 'Andra Brown', 'Counselor, MA, LMHC', '', 'Being a Black person in a professional leadership position can be extremely tough, to say the least. You more than likely received that position due to your uncanny ability of taking care of everybody & everything, and getting sh!t done! Not only are you good at this on the job, but you are typically good at doing this in your personal life. You’re the “responsible” one - the one that everyone in your circles can rely on. While there are benefits from being seen in this manner, you are constantly working, & overworking. Not to mention, working through the microaggressions, and harmful behaviors from other coworkers at work.', 'Manhattan', 'https://www.andrabrown.com/appointments'),
(20, 'Kyle Brown', 'Clinical Social Work/Therapist, LCSW, SEP', '', 'You deserve to be in community with people who support and uplift you. Far too often, people are judged by many mental health professionals. As a black queer non-binary therapist, my ultimate goal is to support you. I have extensive experience providing psychotherapy to LGBTQIA+ and BIPOC communities, and allies. I can be particularly helpful in helping you develop more self-acceptance, more insight, and teach you different tools to support your mental health and well-being. Let’s collaborate to find what works best for you.', 'Manhattan', 'https://www.itsavibepsychotherapy.com'),
(21, 'Dr. Keoshia Worthy', 'Psychologist, PhD, MS', '', 'Hello, my name is Dr. Keoshia Worthy and thank you for visiting my profile. The question that I am frequently asked is, “How do I know if I need therapy?” I like to approach that question by considering the common misconceptions and benefits of therapy. Therapy is not just for people with mental illnesses, someone grieving a loss, or someone who experienced a trauma. Therapy is for anyone, even the well-adjusted person. I believe the benefits from therapy are vast and vary from person to person. For example, therapy can reduce stress, improve relationships, and help with decision-making.', 'Manhattan', 'http://www.worthytherapy.com'),
(22, 'Michael Snipe Jr.', 'Pre-Licensed Professional, LP-MFT', '', 'As a person of intersecting marginalized communities, I understand the need for a safe space to process life’s ups and downs. Thats why creating a therapeutic alliance with you to feel seen, heard and understood is of utmost importance to me. I am here to accompany you on this journey to help you better deal with any stressors or trauma. We will work together to overcome the seen and unseen obstacles in your life and find a more balanced way of living.', 'Manhattan', 'https://www.equitytherapy.com'),
(23, 'Zonya Mitchell Neuropsychologist', 'Psychologist', '', 'When conducting neuropsychological testing, my mission is to provide a warm and caring environment and to see the complete person so that you leave feeling like you have been heard. As a trained neuropsychologist I understand neurological and neurodevelopmental disorders, as well as attention and learning difficulties and how they affect abilities. Psychological/neuropsychological evaluations include assessment of all brain functioning, academic performance, language, and social/emotional development. My aim is to help determine how you or your child are functioning now and how to best help you move forward.', 'Manhattan', 'https://nycneuropsycheval.com'),
(24, 'Paul Geovani Bonilla Jaime', 'Marriage & Family Therapist, LMFT, MS', '', 'Finding it challenging to connect with yourself or your loved ones? Perhaps daily stressors are taking a toll on your well-being? As a Licensed Marriage and Family Therapist, I am here to walk with you on a path of exploration and growth. Whether you are an individual seeking personal development or a couple navigating the complexities of your relationship, I am dedicated to helping you achieve your goals.In working with couples, I focus on identifying strengths and improving communication while addressing concerns such as infidelity, conflict resolution and cultural differences.For individuals, a safe space for exploring concerns.', 'Manhattan', 'https://headway.co/providers/paul-bonilla-jaime?utm_source=pem&utm_medium=direct_link&utm_campaign=93102'),
(25, 'Dru Collins-Minch', 'LPC-A, LAC, MHC-LP, CTP, RYT-200', '', 'I’m a therapist who uses an approach that blends mindfulness, personal values, and an understanding of how our life experiences shape us. I am all about creating space for your feelings—good and bad—while focusing on what truly matters to you. My aim is to help you manage symptoms and guide you in building healthier relationships with yourself, your thoughts, and those around you. I’d like to welcome you to a space where your thoughts, emotions, and relationships are taken seriously, with compassion and care. Together, we will explore ways to live a life aligned with your values, even in the face of challenges.', 'Manhattan', 'https://mcmcollab.com/therapists/dru-collins-minch'),
(26, 'Lindsey Washington', 'Licensed Master Social Worker, LMSW, LSW', '', 'Are you having trouble in your relationship? Are you looking to connect more deeply with your partner or find yourself in the same fights over and over? I specialize in working with couples and individuals who are struggling to with communication, dealing with unhealthy patterns, and who are tired of repeating the same cycles. Whether you are single, in a relationship or married, working, in school or figuring out your next steps, I can help!', 'Manhattan', 'https://sohumtherapy.com/therapists/lindsey-washington'),
(27, 'Khadijah Cyril', 'Psychologist, PhD', '', 'Accepting a New Client. I am so proud of the courage that it took you to look for a therapist. I may not know your full story yet, but I am here to get to know you and help you. If you are someone who feels sad more days than not, has lost pleasure in things you once enjoyed, worry or fearful about your present or future, struggle with relationships, or experienced sensitive events that you do not talk about with others, I am here to help. Also, if you are a parent and this information reflects your child, I specialize in working with them too!', 'Manhattan', 'https://drkhadijahcyril.com'),
(28, 'Kind Mind Psychology', 'Psychologist, PsyD', '', 'Are you stuck in unhealthy patterns? Easily overwhelmed by emotions? Stressed, pressed, and depressed? Do you want to get life moving in the right direction? Are you looking for providers who understand the challenges unique to your experiences as a BIPOC person or member of the LGBTQ+ community? We are here to help! The world can be a scary place, but with us by your side, we can can build a life that makes you happy to wake up each morning. We will create a safe, compassionate space for you to explore your concerns, fears, and shame while giving you the tools to propel yourself forward and build a new world for yourself!', 'Manhattan', 'https://www.kindmindpsych.com'),
(29, 'Steven P Welch', 'Clinical Social Work/Therapist, LCSW-R, ACSW, CCTP', '', 'Congratulations, you have found a compassionate and affirming therapist. I will work with you to assist in your understanding of the COVID, cultural, social and spiritual factors impacting your self image and sense of worth. I provide services to individuals, couples and families. I specialize in the following areas: depression, anxiety, LGBTQ issues, addictions, codependency (divorce/separation) and bereavement.', 'Manhattan', 'https://www.newyork-therapy.com'),
(30, 'Jean-Paul Dugue', 'Clinical Social Work/Therapist, LCSW', '', 'The mind is a powerful tool, incredibly powerful. We can think positive thoughts, we can think realistic thoughts and we can think negative thoughts. Some thoughts are fleeting and others forgotten. Some thoughts are rooted in our early impression of the world around us. We are committed to providing support with negative thought patterns and emotional dysregulation, providing individuals with the tools, knowledge, and the resources to overcome these challenges.', 'Manhattan', 'https://headway.co/providers/jean-paul-dugue');
